{"Question": "How can I combine multiple anomaly detection methods for better results?", "Context": "I want to use ensemble methods to combine different anomaly detection approaches and get more robust results.", "Code_Example": "from anomalydetection import AnomalyPipe, batch_detect_anomalies

# Define multiple detection methods
methods = [
    {
        'name': 'statistical_outliers',
        'params': {
            'columns': 'sensor_reading',
            'method': 'zscore',
            'threshold': 2.5
        }
    },
    {
        'name': 'contextual_anomalies',
        'params': {
            'columns': 'sensor_reading',
            'time_column': 'timestamp',
            'method': 'residual',
            'model_type': 'ewm',
            'threshold': 2.0
        }
    },
    {
        'name': 'collective_anomalies',
        'params': {
            'columns': ['sensor_reading', 'temperature', 'humidity'],
            'time_column': 'timestamp',
            'method': 'isolation_forest',
            'contamination': 0.05
        }
    }
]

# Apply ensemble detection with majority voting
ensemble_results = pipeline | batch_detect_anomalies(
    columns='sensor_reading',
    methods=methods,
    ensemble_method='majority',
    output_suffix='_ensemble_anomaly'
)

print(f"Ensemble anomalies (majority vote): {ensemble_results.data['sensor_reading_ensemble_anomaly'].sum()}")

# Try different ensemble methods
weighted_results = pipeline | batch_detect_anomalies(
    columns='sensor_reading',
    methods=methods,
    ensemble_method='weighted'
)

print(f"Ensemble anomalies (weighted): {weighted_results.data['sensor_reading_ensemble_anomaly'].sum()}")", "Usage": "batch_detect_anomalies(columns='sensor_reading', methods=[{'name': 'statistical_outliers', 'params': {...}}, {'name': 'contextual_anomalies', 'params': {...}}], ensemble_method='majority')"}
